-- Shared CAPA foundation. It reuses tenant scope, reference data, workflow, reporting, audit, and the trusted storage-service contract.
do $$ begin create type public.capa_status as enum ('draft','submitted','under_review','approved','in_progress','pending_evidence','pending_effectiveness_review','effective','ineffective','reopened','completed','closed','rejected','cancelled','overdue','archived'); exception when duplicate_object then null; end $$;
do $$ begin create type public.capa_action_status as enum ('planned','assigned','in_progress','blocked','pending_evidence','pending_verification','completed','rejected','cancelled','overdue'); exception when duplicate_object then null; end $$;
insert into public.permissions(key,name_ar,name_en) values ('capa.view','عرض الإجراءات التصحيحية','View CAPA'),('capa.create','إنشاء إجراء تصحيحي','Create CAPA'),('capa.edit','تعديل مسودة CAPA','Edit CAPA draft'),('capa.submit','إرسال CAPA','Submit CAPA'),('capa.review','مراجعة CAPA','Review CAPA'),('capa.approve','اعتماد CAPA','Approve CAPA'),('capa.assign','تعيين CAPA','Assign CAPA'),('capa.start','بدء CAPA','Start CAPA'),('capa.add_actions','إضافة إجراءات','Add CAPA actions'),('capa.complete_actions','إكمال الإجراءات','Complete CAPA actions'),('capa.upload_evidence','رفع الأدلة','Upload CAPA evidence'),('capa.review_effectiveness','مراجعة الفاعلية','Review effectiveness'),('capa.close','إغلاق CAPA','Close CAPA'),('capa.reopen','إعادة فتح CAPA','Reopen CAPA'),('capa.reject','رفض CAPA','Reject CAPA'),('capa.cancel','إلغاء CAPA','Cancel CAPA'),('capa.extend_due_date','تمديد الاستحقاق','Extend CAPA due date'),('capa.archive','أرشفة CAPA','Archive CAPA'),('capa.restore','استعادة CAPA','Restore CAPA'),('capa.view_history','عرض سجل CAPA','View CAPA history'),('capa.view_confidential','عرض CAPA السري','View confidential CAPA'),('capa.manage_configuration','إدارة إعدادات CAPA','Manage CAPA configuration'),('capa.export','تصدير CAPA','Export CAPA'),('capa.view_dashboard','عرض لوحة CAPA','View CAPA dashboard'),('capa.override_assignment','تجاوز التعيين','Override CAPA assignment'),('capa.override_separation_of_duties','تجاوز فصل المهام','Override CAPA separation of duties') on conflict(key) do nothing;
insert into public.role_permissions(role_id,permission_id) select r.id,p.id from public.roles r join public.permissions p on p.key like 'capa.%' where r.key='platform_owner' on conflict do nothing;
create table public.capa_records(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),department_id uuid references public.departments(id),capa_number text not null,title_ar text,title_en text,description_ar text,description_en text,status public.capa_status not null default 'draft',type_reference_id uuid references public.reference_data_items(id),category_reference_id uuid references public.reference_data_items(id),priority_reference_id uuid references public.reference_data_items(id),risk_reference_id uuid references public.reference_data_items(id),severity_reference_id uuid references public.reference_data_items(id),owner_id uuid not null references public.user_profiles(id),responsible_department_id uuid references public.departments(id),approver_id uuid references public.user_profiles(id),reviewer_id uuid references public.user_profiles(id),target_completion_date date,actual_completion_date date,review_date date,effectiveness_review_date date,root_cause_method_reference_id uuid references public.reference_data_items(id),root_cause_summary text,immediate_containment text,corrective_action_summary text,preventive_action_summary text,effectiveness_criteria text,closure_decision text,rejection_reason text,cancellation_reason text,extension_reason text,confidentiality_level text not null default 'normal' check(confidentiality_level in ('normal','confidential','restricted')),tags text[] not null default '{}',workflow_instance_id uuid references public.workflow_instances(id),created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid not null references public.user_profiles(id),closed_at timestamptz,closed_by uuid references public.user_profiles(id),archived_at timestamptz,archived_by uuid references public.user_profiles(id),check(coalesce(nullif(title_ar,''),nullif(title_en,'')) is not null),unique(tenant_id,organization_id,facility_id,capa_number));
create table public.capa_sources(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),source_module text not null,source_record_type text not null,source_record_id uuid,source_finding_id uuid,created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id),unique(capa_id,source_module,source_record_type,source_record_id));
create table public.capa_actions(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),sequence integer not null check(sequence>=0),title_ar text,title_en text,description_ar text,description_en text,action_type_reference_id uuid references public.reference_data_items(id),assigned_user_id uuid references public.user_profiles(id),assigned_department_id uuid references public.departments(id),planned_start_date date,due_date date,actual_start_date date,completion_date date,status public.capa_action_status not null default 'planned',priority_reference_id uuid references public.reference_data_items(id),evidence_required boolean not null default false,completion_notes text,verification_user_id uuid references public.user_profiles(id),verification_date date,verification_result text,rejection_reason text,depends_on_action_id uuid references public.capa_actions(id),unique(capa_id,sequence));
create table public.capa_root_cause_analyses(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),method_reference_id uuid references public.reference_data_items(id),problem_statement text not null,contributing_factors text[] not null default '{}',root_cause_summary text,conclusion text,participants uuid[] not null default '{}',reviewed_by uuid references public.user_profiles(id),review_date date,created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id));
create table public.capa_effectiveness_reviews(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),reviewer_id uuid not null references public.user_profiles(id),criteria text not null,evidence_summary text,quantitative_result text,qualitative_result text,result text not null check(result in ('effective','partially_effective','ineffective')),follow_up_required boolean not null default false,reopen_decision boolean not null default false,comments text,created_at timestamptz not null default now());
create table public.capa_due_date_extensions(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),old_due_date date not null,requested_due_date date not null,reason text not null,status text not null default 'requested' check(status in ('requested','approved','rejected')),requested_by uuid not null references public.user_profiles(id),requested_at timestamptz not null default now(),decided_by uuid references public.user_profiles(id),decided_at timestamptz,decision_comment text);
create table public.capa_assignments(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),user_id uuid not null references public.user_profiles(id),created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id),unique(capa_id,user_id));
create table public.capa_comments(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,action_id uuid references public.capa_actions(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),body text not null,confidential boolean not null default false,created_at timestamptz not null default now(),created_by uuid not null references public.user_profiles(id));
create table public.capa_evidence(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,action_id uuid references public.capa_actions(id),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),storage_bucket text not null,storage_key text not null,checksum text not null,mime_type text not null,byte_size bigint not null,scan_status text not null default 'pending',uploaded_by uuid not null references public.user_profiles(id),created_at timestamptz not null default now());
create table public.capa_events(id uuid primary key default gen_random_uuid(),capa_id uuid not null references public.capa_records(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),actor_id uuid not null references public.user_profiles(id),action text not null,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create or replace function public.can_capa(p_permission text,p_t uuid,p_o uuid,p_f uuid) returns boolean language sql stable security definer set search_path=public as $$ select auth.uid() is not null and public.scope_allowed(p_t,p_o,p_f) and (public.has_platform_permission(p_permission,p_t,p_o,p_f) or public.has_platform_permission('platform.full_access',p_t,p_o,p_f)); $$;
create or replace function public.capa_source_allowed(p_module text,p_type text,p_id uuid,p_t uuid,p_o uuid,p_f uuid) returns boolean language plpgsql security definer set search_path=public as $$ begin if p_module='manual' and p_type='manual' and p_id is null then return true; end if; if p_module='medication_errors' and p_type='medication_error' then return exists(select 1 from public.medication_error_reports x where x.id=p_id and x.tenant_id=p_t and x.organization_id=p_o and x.facility_id is not distinct from p_f); end if; if p_module='policies' and p_type='policy' then return exists(select 1 from public.policy_definitions x where x.id=p_id and x.tenant_id=p_t and x.organization_id=p_o and x.facility_id is not distinct from p_f); end if; raise exception 'CAPA source adapter is not implemented'; end $$;
create or replace function public.record_capa_event(p_capa uuid,p_t uuid,p_o uuid,p_f uuid,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ begin if auth.uid() is null or current_setting('app.capa_controlled',true)<>'on' then raise exception 'CAPA event is not authorized'; end if; insert into public.capa_events(capa_id,tenant_id,organization_id,facility_id,actor_id,action,metadata) values(p_capa,p_t,p_o,p_f,auth.uid(),p_action,p_metadata); perform public.append_reporting_audit_event(p_t,p_o,p_f,p_action,'capa_record',p_capa,p_metadata); end $$;
create or replace function public.create_capa(p_t uuid,p_o uuid,p_f uuid,p_title_ar text,p_title_en text,p_description_ar text,p_description_en text,p_owner uuid,p_source_module text default 'manual',p_source_type text default 'manual',p_source_id uuid default null) returns uuid language plpgsql security definer set search_path=public as $$ declare id uuid; number text; begin if not public.can_capa('capa.create',p_t,p_o,p_f) or not public.policy_member_in_scope(p_owner,p_t,p_o,p_f) or not public.capa_source_allowed(p_source_module,p_source_type,p_source_id,p_t,p_o,p_f) then raise exception 'CAPA creation denied'; end if; number:='CAPA-'||to_char(now(),'YYYY')||'-'||substr(gen_random_uuid()::text,1,8); perform set_config('app.capa_controlled','on',true); perform set_config('app.reporting_audit','on',true); insert into public.capa_records(tenant_id,organization_id,facility_id,capa_number,title_ar,title_en,description_ar,description_en,owner_id,created_by,updated_by) values(p_t,p_o,p_f,number,nullif(trim(p_title_ar),''),nullif(trim(p_title_en),''),nullif(trim(p_description_ar),''),nullif(trim(p_description_en),''),p_owner,auth.uid(),auth.uid()) returning id into id; insert into public.capa_sources(capa_id,tenant_id,organization_id,facility_id,source_module,source_record_type,source_record_id,created_by) values(id,p_t,p_o,p_f,p_source_module,p_source_type,p_source_id,auth.uid()); perform public.record_capa_event(id,p_t,p_o,p_f,'capa.created'); return id; end $$;
create or replace function public.transition_capa(p_capa uuid,p_to public.capa_status,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare c public.capa_records%rowtype; required text; begin select * into c from public.capa_records where id=p_capa for update; if not found then raise exception 'CAPA transition denied'; end if; required:=case p_to when 'submitted' then 'capa.submit' when 'under_review' then 'capa.review' when 'approved' then 'capa.approve' when 'in_progress' then 'capa.start' when 'closed' then 'capa.close' when 'reopened' then 'capa.reopen' when 'rejected' then 'capa.reject' when 'cancelled' then 'capa.cancel' when 'archived' then 'capa.archive' else 'capa.edit' end; if not public.can_capa(required,c.tenant_id,c.organization_id,c.facility_id) or (p_to in ('rejected','cancelled','reopened') and coalesce(trim(p_reason),'')='') or (p_to='approved' and (auth.uid()=c.created_by or auth.uid()=c.owner_id) and not public.can_capa('capa.override_separation_of_duties',c.tenant_id,c.organization_id,c.facility_id)) or (p_to='closed' and auth.uid()=c.owner_id and not public.can_capa('capa.override_separation_of_duties',c.tenant_id,c.organization_id,c.facility_id)) then raise exception 'CAPA transition denied'; end if; perform set_config('app.capa_controlled','on',true); perform set_config('app.reporting_audit','on',true); update public.capa_records set status=p_to,closed_at=case when p_to='closed' then now() else closed_at end,closed_by=case when p_to='closed' then auth.uid() else closed_by end,updated_at=now(),updated_by=auth.uid() where id=c.id; perform public.record_capa_event(c.id,c.tenant_id,c.organization_id,c.facility_id,'capa.'||p_to::text,jsonb_build_object('reason',p_reason)); end $$;
create or replace function public.assign_capa_action(p_capa uuid,p_title_ar text,p_title_en text,p_assignee uuid,p_due date) returns uuid language plpgsql security definer set search_path=public as $$ declare c public.capa_records%rowtype; id uuid; begin select * into c from public.capa_records where id=p_capa for update; if not found or c.status not in ('approved','in_progress','reopened') or not public.can_capa('capa.add_actions',c.tenant_id,c.organization_id,c.facility_id) or not public.policy_member_in_scope(p_assignee,c.tenant_id,c.organization_id,c.facility_id) then raise exception 'CAPA action assignment denied'; end if; perform set_config('app.capa_controlled','on',true); perform set_config('app.reporting_audit','on',true); insert into public.capa_actions(capa_id,tenant_id,organization_id,facility_id,sequence,title_ar,title_en,assigned_user_id,due_date,status) values(c.id,c.tenant_id,c.organization_id,c.facility_id,(select coalesce(max(sequence),-1)+1 from public.capa_actions where capa_id=c.id),nullif(trim(p_title_ar),''),nullif(trim(p_title_en),''),p_assignee,p_due,'assigned') returning id into id; perform public.record_capa_event(c.id,c.tenant_id,c.organization_id,c.facility_id,'capa.action_assigned',jsonb_build_object('action_id',id)); return id; end $$;
create or replace function public.record_capa_effectiveness(p_capa uuid,p_result text,p_comments text,p_reopen boolean) returns uuid language plpgsql security definer set search_path=public as $$ declare c public.capa_records%rowtype; id uuid; begin select * into c from public.capa_records where id=p_capa for update; if not found or c.status not in ('pending_effectiveness_review','completed') or not public.can_capa('capa.review_effectiveness',c.tenant_id,c.organization_id,c.facility_id) or auth.uid()=c.owner_id then raise exception 'CAPA effectiveness review denied'; end if; perform set_config('app.capa_controlled','on',true); perform set_config('app.reporting_audit','on',true); insert into public.capa_effectiveness_reviews(capa_id,tenant_id,organization_id,facility_id,reviewer_id,criteria,result,reopen_decision,comments) values(c.id,c.tenant_id,c.organization_id,c.facility_id,auth.uid(),'Configured effectiveness criteria',p_result,p_reopen,p_comments) returning id into id; update public.capa_records set status=case when p_reopen or p_result='ineffective' then 'reopened' else 'effective' end,updated_at=now(),updated_by=auth.uid() where id=c.id; perform public.record_capa_event(c.id,c.tenant_id,c.organization_id,c.facility_id,'capa.effectiveness_recorded',jsonb_build_object('review_id',id,'result',p_result)); return id; end $$;
create or replace function public.enforce_capa_scope() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name='capa_actions' and not exists(select 1 from public.capa_records c where c.id=new.capa_id and c.tenant_id=new.tenant_id and c.organization_id=new.organization_id and c.facility_id is not distinct from new.facility_id) then raise exception 'CAPA action scope mismatch' using errcode='23503'; end if; if tg_table_name='capa_sources' and not exists(select 1 from public.capa_records c where c.id=new.capa_id and c.tenant_id=new.tenant_id and c.organization_id=new.organization_id and c.facility_id is not distinct from new.facility_id) then raise exception 'CAPA source scope mismatch' using errcode='23503'; end if; if tg_table_name in ('capa_actions','capa_assignments') and new.assigned_user_id is not null and not public.policy_member_in_scope(new.assigned_user_id,new.tenant_id,new.organization_id,new.facility_id) then raise exception 'CAPA assignee outside scope' using errcode='23503'; end if; return new; end $$;
create trigger capa_actions_scope before insert or update on public.capa_actions for each row execute function public.enforce_capa_scope(); create trigger capa_sources_scope before insert or update on public.capa_sources for each row execute function public.enforce_capa_scope();
alter table public.capa_records enable row level security; alter table public.capa_sources enable row level security; alter table public.capa_actions enable row level security; alter table public.capa_root_cause_analyses enable row level security; alter table public.capa_effectiveness_reviews enable row level security; alter table public.capa_due_date_extensions enable row level security; alter table public.capa_assignments enable row level security; alter table public.capa_comments enable row level security; alter table public.capa_evidence enable row level security; alter table public.capa_events enable row level security;
create policy capa_records_read on public.capa_records for select using((status not in ('archived','closed') and public.can_capa('capa.view',tenant_id,organization_id,facility_id) and (confidentiality_level='normal' or public.can_capa('capa.view_confidential',tenant_id,organization_id,facility_id))) or (status in ('archived','closed') and public.can_capa('capa.view_history',tenant_id,organization_id,facility_id)) or public.can_capa('capa.edit',tenant_id,organization_id,facility_id) or public.can_capa('capa.review',tenant_id,organization_id,facility_id) or public.can_capa('capa.approve',tenant_id,organization_id,facility_id));
create policy capa_children_read on public.capa_actions for select using(exists(select 1 from public.capa_records c where c.id=capa_id and public.can_capa('capa.view',c.tenant_id,c.organization_id,c.facility_id))); create policy capa_events_read on public.capa_events for select using(public.can_capa('capa.view_history',tenant_id,organization_id,facility_id)); create policy capa_comments_read on public.capa_comments for select using(public.can_capa('capa.view',tenant_id,organization_id,facility_id) and (not confidential or public.can_capa('capa.view_confidential',tenant_id,organization_id,facility_id)));
revoke all on function public.can_capa(text,uuid,uuid,uuid),public.capa_source_allowed(text,text,uuid,uuid,uuid,uuid),public.record_capa_event(uuid,uuid,uuid,uuid,text,jsonb),public.enforce_capa_scope() from public,anon; grant execute on function public.can_capa(text,uuid,uuid,uuid),public.create_capa(uuid,uuid,uuid,text,text,text,text,uuid,text,text,uuid),public.transition_capa(uuid,public.capa_status,text),public.assign_capa_action(uuid,text,text,uuid,date),public.record_capa_effectiveness(uuid,text,text,boolean) to authenticated; revoke all on function public.record_capa_event(uuid,uuid,uuid,uuid,text,jsonb),public.enforce_capa_scope() from authenticated;
